[DataContractAttribute]
public class HDG_PurchReceiptContract
{
    private PurchId purchId;
    private TradeLineNumber lineNumber;
    private PurchQty receiveQty;
    private InventDimId inventDimId;

}

Method.Source:
[DataMemberAttribute("PurchId")]
public PurchId parmPurchId(PurchId _purchId = purchId)
{
    purchId = _purchId;
    return purchId;
}

[DataMemberAttribute("LineNumber")]
public TradeLineNumber parmLineNumber(TradeLineNumber _lineNumber = lineNumber)
{
    lineNumber = _lineNumber;
    return lineNumber;
}

[DataMemberAttribute("ReceiveQty")]
public PurchQty parmReceiveQty(PurchQty _receiveQty = receiveQty)
{
    receiveQty = _receiveQty;
    return receiveQty;
}

[DataMemberAttribute("InventDimId")]
public InventDimId parmInventDimId(InventDimId _inventDimId = inventDimId)
{
    inventDimId = _inventDimId;
    return inventDimId;
}
